import { mathMax } from '../core/zc-constants';

/**
 *
 * @param context
 * @param node
 * @param nodeOptions
 * @param minHeight
 */
export function drawSankeyNode(context, node, nodeOptions, minHeight = 0) {
    if (isNaN(node.x0)) {
        node.x0 = 0;
    }
    if (isNaN(node.x1)) {
        node.x1 = nodeOptions.width;
    }
    context.moveTo(node.x0, node.y0);
    context.lineTo(node.x1, node.y0);
    context.lineTo(node.x1, node.y1);
    context.lineTo(node.x0, node.y1);
    context.closePath();

    // TODO configurable
    // for hover
    minHeight = 4;
    let height = node.y1 - node.y0,
        yCenter = node.y0 + height / 2,
        { y0, y1 } = node;

    if (height < minHeight) {
        y0 = yCenter - minHeight / 2;
        y1 = yCenter + minHeight / 2;
    }

    // poly
    node._polypoints = [
        [node.x0, y0],
        [node.x1, y0],
        [node.x1, y1],
        [node.x0, y1]
    ];
}
